class Page(BasePage[TAny], Generic[TAny]):
    page: GreaterEqualOne
    size: GreaterEqualOne
    pages: GreaterEqualZero

    __params_type__ = Params

    @classmethod
    def create(
        cls,
        items: Sequence[TAny],
        params: AbstractParams,
        *,
        total: int | None = None,
        **kwargs: Any,
    ) -> Page[TAny]:
        if not isinstance(params, Params):
            raise TypeError("Page should be used with Params")

        size = params.size if params.size is not None else (total or None)
        page = params.page if params.page is not None else 1

        if size in {0, None}:
            pages = 0
        elif total is not None:
            pages = ceil(total / size)
        else:
            pages = None

        return create_pydantic_model(
            cls,
            total=total,
            items=items,
            page=page,
            size=size,
            pages=pages,
            **kwargs,
        )

async def __call__(self, request: Request, handler):
        if self.should_validate_client_ip():
            self.validate_proxy_ip(ip_address(request.client_ip))

        headers = request.headers
        forwarded_for = self.get_forwarded_for(headers)
        forwarded_host = self.get_forwarded_host(headers)
        forwarded_proto = self.get_forwarded_proto(headers)

        if forwarded_host:
            self.validate_host(forwarded_host)

            request.host = forwarded_host
        else:
            # validate the host from the Host header anyway
            self.validate_host(request.host)

        if forwarded_for:
            self.validate_forwarded_for(forwarded_for)

            request.original_client_ip = str(forwarded_for[0])

        if forwarded_proto:
            self.validate_forwarded_proto(forwarded_proto)

            request.scheme = forwarded_proto[0]

        return await handler(request)

def use_authentication(
        self,
        strategy: AuthenticationStrategy | None = None,
        rate_limiter: RateLimiter | None = None,
    ) -> AuthenticationStrategy:
        if self.started:
            raise RuntimeError(
                "The application is already running, configure authentication "
                "before starting the application"
            )

        if self._authentication_strategy:
            return self._authentication_strategy

        if not strategy:
            strategy = AuthenticationStrategy(
                container=self.services,
                rate_limiter=rate_limiter,
                logger=self.logger,
            )

        self._authentication_strategy = strategy

        self.middlewares.append(
            get_authentication_middleware(self._authentication_strategy),
            MiddlewareCategory.AUTH,
        )
        return strategy

def create_publisher_fake_subscriber(
        self,
        broker: KafkaBroker,
        publisher: "LogicPublisher",
    ) -> tuple["LogicSubscriber[Any]", bool]:
        sub: LogicSubscriber[Any] | None = None
        for handler in (s for b in self.brokers for s in b.subscribers):
            handler = cast("LogicSubscriber[Any]", handler)
            if _is_handler_matches(handler, publisher.topic, publisher.partition):
                sub = handler
                break

        if sub is None:
            is_real = False

            topic_name = publisher.topic

            if publisher.partition:
                tp = TopicPartition(
                    topic=topic_name,
                    partition=publisher.partition,
                )
                sub = broker.subscriber(
                    partitions=[tp],
                    batch=isinstance(publisher, BatchPublisher),
                    persistent=False,
                )
            else:
                sub = broker.subscriber(
                    topic_name,
                    batch=isinstance(publisher, BatchPublisher),
                    persistent=False,
                )
        else:
            is_real = True

        return sub, is_real

def from_sub(cls, binding: SpecBinding | None) -> Self | None:
        if binding is None:
            return None

        if binding.amqp and (
            amqp := amqp_bindings.OperationBinding.from_sub(binding.amqp)
        ):
            return cls(amqp=amqp)

        if binding.kafka and (
            kafka := kafka_bindings.OperationBinding.from_sub(binding.kafka)
        ):
            return cls(kafka=kafka)

        if binding.mqtt and (
            mqtt := mqtt_bindings.OperationBinding.from_sub(binding.mqtt)
        ):
            return cls(mqtt=mqtt)

        if binding.nats and (
            nats := nats_bindings.OperationBinding.from_sub(binding.nats)
        ):
            return cls(nats=nats)

        if binding.redis and (
            redis := redis_bindings.OperationBinding.from_sub(binding.redis)
        ):
            return cls(redis=redis)

        if binding.sqs and (sqs := sqs_bindings.OperationBinding.from_sub(binding.sqs)):
            return cls(sqs=sqs)

        return None

